scwin.gr_paymentDt_oncellclick = function (rowIndex, columnIndex, columnId) {
  if (scwin.vAuthYn == "Y") {
    if (ds_paymentDt.getRowStatus(rowIndex) == "C") {
      gr_paymentDt.setColumnReadOnly("paymentDt", false);
    } else {
      gr_paymentDt.setColumnReadOnly("paymentDt", true);
    }
  } else {
    gr_paymentDt.setColumnReadOnly("paymentDt", true);
  }
};
scwin.gr_additionalValue_oncellclick = function (rowIndex, columnIndex, columnId) {
  if (ds_additionalValue.getRowStatus(rowIndex) == "C") {
    gr_additionalValue.setColumnReadOnly("additionalKndCd", false);
    gr_additionalValue.setColumnReadOnly("crcCd", false);
    gr_additionalValue.setColumnReadOnly("stdDt", false);
  } else {
    gr_additionalValue.setColumnReadOnly("additionalKndCd", true);
    gr_additionalValue.setColumnReadOnly("crcCd", true);
    gr_additionalValue.setColumnReadOnly("stdDt", false);
  }
};
scwin.ds_additionalValue_oncelldatachange = function (info) {
  let row = info.row;
  let colid = info.colId;
  if (colid == "additionalKndCd") {
    let val = ds_additionalValue.getCellData(row, "additionalKndCd");
    if (val == "1" || val == "2" || val == "3") {
      ds_additionalValue.setCellData(row, "gubun", "1");
    } else if (val == "4" || val == "5") {
      ds_additionalValue.setCellData(row, "gubun", "2");
    }
  }
};
scwin.acb_ramtCrcCd_onchange = function (e) {
  scwin.f_getRamt();
};
